import type { Stream, Writer } from "@rdfc/js-runner";
import type { BlankNode, NamedNode, Quad, Term } from "@rdfjs/types";
import { RdfStore } from "rdf-stores";
export type NBNode = NamedNode | BlankNode;
export type ShapeTransform = (id: Term | undefined, store: RdfStore) => Term | undefined;
export type AddProcess = (used: Term | undefined, store: RdfStore) => Term;
export type DatasetTransform = (used: Term | undefined, store: RdfStore) => Term;
export type QuadsTransform = (quads: Quad[]) => Promise<Quad[]>;
export declare function getLatestStream(store: RdfStore): Promise<NBNode | undefined>;
export declare function getLatestShape(streamId: Term, store: RdfStore): Promise<NBNode | undefined>;
export declare function transformMetadata(streamId: Term, sourceStream: Term | undefined, itemType: string, gp: AddProcess, shT?: ShapeTransform, datasetT?: DatasetTransform): QuadsTransform;
export declare function createProperty(store: RdfStore, path: NBNode, dataType?: NBNode, nodeKind?: NBNode, minCount?: number, maxCount?: number): BlankNode | NamedNode;
export type SR<T> = {
    [P in keyof T]: Stream<T[P]>;
};
export type SW<T> = {
    [P in keyof T]: Writer<T[P]>;
};
